import { useEffect, useState } from "react";
import { getEvidenciaById } from "../backend/controllers/evidencias";

const FantasmaCard = ({ fantasma }) => {
  const [prueba, setPrueba] = useState([]);

  useEffect(() => {
    getEvidenciaById(fantasma.id)
            .then((evidencias) => setPruebas(evidencias))
            .catch((error) => console.error("Error fetching evidencias:", error));
    }, [fantasma.id]);
  return (
    <>
      <tr>
        <td>{fantasma.nombre}</td>
        <td>{prueba?.prueba}</td>
        <td>Manetta</td>
        <td>Una</td>
        <td>1</td>
      </tr>
    </>
  );
};

export default FantasmaCard;
